202	  template <class ProblemShape>
203	  static constexpr Params
204	  to_underlying_arguments(ProblemShape const& problem_shape, Arguments const& args, void* workspace) {
205	    (void) workspace;
206	
207	    // Optionally append 1s until problem shape is rank-4 (MNKL), in case it is only rank-3 (MNK)
208	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
209	    auto [M,N,K,L] = problem_shape_MNKL;
210	
211	    auto ptr_A = reinterpret_cast<InternalElementA const*>(args.ptr_A);
212	    auto ptr_B = reinterpret_cast<InternalElementB const*>(args.ptr_B);
213	
214	    Tensor tensor_a = make_tensor(ptr_A, make_layout(make_shape(M,K,L), args.dA));
215	    Tensor tensor_b = make_tensor(ptr_B, make_layout(make_shape(N,K,L), args.dB));
216	
217	    typename Params::TMA_A tma_load_a = make_tma_copy_A_sm90(
218	        GmemTiledCopyA{},
219	        tensor_a,
220	        SmemLayoutA{}(_,_,cute::Int<0>{}),
221	        TileShape{},
222	        ClusterShape{});
223	    typename Params::TMA_B tma_load_b = make_tma_copy_B_sm90(
224	        GmemTiledCopyB{},
225	        tensor_b,
226	        SmemLayoutB{}(_,_,cute::Int<0>{}),
227	        TileShape{},
228	        ClusterShape{});
229	    uint32_t transaction_bytes_mk = TmaTransactionBytesMK;
230	    uint32_t transaction_bytes_nk = TmaTransactionBytesNK;
231	    uint32_t transaction_bytes = transaction_bytes_mk + transaction_bytes_nk;
232	
233	    return {
234	      tma_load_a,
235	      tma_load_b,
236	      transaction_bytes,
237	      transaction_bytes_mk,
238	      transaction_bytes_nk
239	    };
240	  }
