242	  template<class ProblemShape>
243	  static bool
244	  can_implement(
245	      ProblemShape const& problem_shape,
246	      [[maybe_unused]] Arguments const& args) {
247	    constexpr int tma_alignment_bits = 128;
248	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
249	    auto [M,N,K,L] = problem_shape_MNKL;
250	
251	    bool implementable = true;
252	    constexpr int min_tma_aligned_elements_A = tma_alignment_bits / cutlass::sizeof_bits<ElementA>::value;
253	    implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_A>(cute::make_shape(M,K,L), StrideA{});
254	    constexpr int min_tma_aligned_elements_B = tma_alignment_bits / cutlass::sizeof_bits<ElementB>::value;
255	    implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_B>(cute::make_shape(N,K,L), StrideB{});
256	
257	    if (!implementable) {
258	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Problem Size doesn't meet the minimum alignment requirements for TMA.\n");
259	    }
260	    return implementable;
261	  }
