278	  /// Set up the data needed by this collective for load and mma.
279	  /// Returns a tuple of tensors. The collective and the kernel layer have the contract
280	  /// Returned tuple must contain at least two elements, with the first two elements being:
281	  /// gA_mkl - The tma tensor, A after a local tile so it has shape  (BLK_M,BLK_K,m,k,l)
282	  /// gB_nkl - The tma tensor, B after a local tile so it has shape  (BLK_N,BLK_K,n,k,l)
283	  /// The rest of the tensors can be specified as needed by this collective.
284	  template <class ProblemShape_MNKL>
285	  CUTLASS_DEVICE auto
286	  load_init(ProblemShape_MNKL const& problem_shape_MNKL, Params const& mainloop_params) const {
287	    using X = Underscore;
288	    // Separate out problem shape for convenience
289	    auto [M,N,K,L] = problem_shape_MNKL;
290	
291	    // TMA requires special handling of strides to deal with coord codomain mapping
292	    // Represent the full tensors -- get these from TMA
293	    Tensor mA_mkl = mainloop_params.tma_load_a.get_tma_tensor(make_shape(M,K,L));                            // (m,k,l)
294	    Tensor mB_nkl = mainloop_params.tma_load_b.get_tma_tensor(make_shape(N,K,L));                            // (n,k,l)
295	
296	    // Make tiled views, defer the slice
297	    Tensor gA_mkl = local_tile(mA_mkl, TileShape{}, make_coord(_,_,_), Step<_1, X,_1>{});        // (BLK_M,BLK_K,m,k,l)
298	    Tensor gB_nkl = local_tile(mB_nkl, TileShape{}, make_coord(_,_,_), Step< X,_1,_1>{});        // (BLK_N,BLK_K,n,k,l)
299	
300	    return cute::make_tuple(gA_mkl, gB_nkl);
301	  }
