303	  /// Perform a collective-scoped matrix multiply-accumulate
304	  /// Producer Perspective
305	  template <
306	    class TensorA, class TensorB,
307	    class KTileIterator, class BlockCoord
308	  >
309	  CUTLASS_DEVICE void
310	  load(
311	      Params const& mainloop_params,
312	      MainloopPipeline pipeline,
313	      PipelineState smem_pipe_write,
314	      cute::tuple<TensorA, TensorB> const& load_inputs,
315	      BlockCoord const& blk_coord,
316	      KTileIterator k_tile_iter, int k_tile_count,
317	      int thread_idx,
318	      uint32_t block_rank_in_cluster,
319	      TensorStorage& shared_tensors) {
320	    int lane_predicate = cute::elect_one_sync();
321	
322	    if (lane_predicate) {
323	      Tensor sA = make_tensor(make_smem_ptr(shared_tensors.smem_A.data()), SmemLayoutA{});        // (BLK_M,BLK_K,PIPE)
324	      Tensor sB = make_tensor(make_smem_ptr(shared_tensors.smem_B.data()), SmemLayoutB{});        // (BLK_N,BLK_K,PIPE)
325	
326	      //
327	      // Prepare the TMA loads for A and B
328	      //
329	
330	      constexpr uint32_t cluster_shape_x = get<0>(typename DispatchPolicy::ClusterShape());
331	      uint2 cluster_local_block_id = {block_rank_in_cluster % cluster_shape_x, block_rank_in_cluster / cluster_shape_x};
332	
333	      Tensor gA_mkl = get<0>(load_inputs);
334	      Tensor gB_nkl = get<1>(load_inputs);
335	
336	      auto block_tma_a = mainloop_params.tma_load_a.get_slice(cluster_local_block_id.y);
337	      auto block_tma_b = mainloop_params.tma_load_b.get_slice(cluster_local_block_id.x);
338	
339	      // Partition the inputs based on the current block coordinates.
340	      auto [m_coord, n_coord, k_coord, l_coord] = blk_coord;
341	      Tensor gA = gA_mkl(_,_,m_coord,_,l_coord);                                                     // (BLK_M,BLK_K,k)
342	      Tensor gB = gB_nkl(_,_,n_coord,_,l_coord);                                                     // (BLK_N,BLK_K,k)
343	
344	      // Applies the mapping from block_tma_a
345	      Tensor tAgA = block_tma_a.partition_S(gA);                                                 // (TMA,TMA_M,TMA_K,k)
346	      Tensor tAsA = block_tma_a.partition_D(sA);                                              // (TMA,TMA_M,TMA_K,PIPE)
347	
348	      Tensor tBgB = block_tma_b.partition_S(gB);                                                 // (TMA,TMA_N,TMA_K,k)
349	      Tensor tBsB = block_tma_b.partition_D(sB);                                              // (TMA,TMA_N,TMA_K,PIPE)
350	
351	      uint16_t mcast_mask_a = 0;
352	      uint16_t mcast_mask_b = 0;
353	
354	      // Issue TmaLoads
355	      // Maps the tile -> block, value
356	      if constexpr (cute::is_same_v<GmemTiledCopyA, SM90_TMA_LOAD_MULTICAST>) {
357	        auto block_layout = Layout<typename DispatchPolicy::ClusterShape>{}; // (m,n) -> block_id
358	        for (int n = 0; n < size<1>(block_layout); ++n) {
359	          mcast_mask_a |= (uint16_t(1) << block_layout(cluster_local_block_id.x,n,Int<0>{}));
360	        }
361	      }
362	
363	      if constexpr (cute::is_same_v<GmemTiledCopyB, SM90_TMA_LOAD_MULTICAST>) {
364	        auto block_layout = Layout<typename DispatchPolicy::ClusterShape>{}; // (m,n) -> block_id
365	        for (int m = 0; m < size<0>(block_layout); ++m) {
366	          mcast_mask_b |= (uint16_t(1) << block_layout(m,cluster_local_block_id.y,Int<0>{}));
367	        }
368	      }
369	
370	      // Mainloop
371	      CUTLASS_PRAGMA_NO_UNROLL
372	      for ( ; k_tile_count > 0; --k_tile_count) {
373	        // LOCK smem_pipe_write for _writing_
374	        pipeline.producer_acquire(smem_pipe_write);
375	
376	        //
377	        // Copy gmem to smem for *k_tile_iter
378	        //
379	
380	        using BarrierType = typename MainloopPipeline::ProducerBarrierType;
381	        BarrierType* tma_barrier = pipeline.producer_get_barrier(smem_pipe_write);
382	
383	        int write_stage = smem_pipe_write.index();
384	        copy(mainloop_params.tma_load_a.with(*tma_barrier, mcast_mask_a), tAgA(_,_,_,*k_tile_iter), tAsA(_,_,_,write_stage));
385	        copy(mainloop_params.tma_load_b.with(*tma_barrier, mcast_mask_b), tBgB(_,_,_,*k_tile_iter), tBsB(_,_,_,write_stage));
386	        ++k_tile_iter;
387	
388	        // Advance smem_pipe_write
389	        ++smem_pipe_write;
390	      }
391	    }
392	  }
