394	  /// Perform a Producer Epilogue to prevent early exit of blocks in a Cluster
395	  CUTLASS_DEVICE void
396	  load_tail(MainloopPipeline pipeline, PipelineState smem_pipe_write) {
397	    int lane_predicate = cute::elect_one_sync();
398	
399	    // Issue the epilogue waits
400	    if (lane_predicate) {
401	      /* This helps avoid early exit of blocks in Cluster
402	       * Waits for all stages to either be released (all
403	       * Consumer UNLOCKs), or if the stage was never used
404	       * then would just be acquired since the phase was
405	       * still inverted from make_producer_start_state
406	       */
407	      pipeline.producer_tail(smem_pipe_write);
408	    }
409	  }
